import React from 'react';
import { motion } from 'framer-motion';

const About = () => (
  <motion.main initial={{opacity:0, y:30}} animate={{opacity:1, y:0}} transition={{duration:0.8}}>
    <h2>About AI Quiz Builder</h2>
    <p>
      This project is inspired by the best in the industry, blending dynamic design and seamless user experience. Our mission is to make quiz creation fun, interactive, and visually stunning.
    </p>
    <p>
      Built with React, Framer Motion, and Lottie for a modern, animated web experience.
    </p>
  </motion.main>
);

export default About;
